@Controller('api/runs/:runId')
@UseGuards(AuthGuard)
export class RunsController {
  @Get('comparison')
  @Roles('viewer')
  getComparison() {
    return this.service.getComparison();
  }

  @Post('retry-child-extraction')
  @Roles('admin', 'ops')
  retryChildExtraction() {
    return this.service.retryChildExtraction();
  }

  @Post('override-comparison')
  @Roles('admin')
  overrideComparison() {
    return this.service.createUpdatedRun();
  }

  @Delete('comparison')
  deleteComparison() {
    return this.service.deleteComparison();
  }
}

